import org.springframework.beans.factory.annotation.*;
import org.springframework.context.annotation.*;
import org.springframework.stereotype.*;
import jakarta.annotation.*;

// ── Interfaces ──────────────────────────────────────────────────
interface NotificationService { void send(String msg); }
interface UserRepository { String findById(int id); }

// ── Implementations ─────────────────────────────────────────────
@Service
class EmailNotificationService implements NotificationService {
    @Override public void send(String msg) { System.out.println("Email: " + msg); }
}

@Repository
class InMemoryUserRepository implements UserRepository {
    @Override public String findById(int id) { return "User#" + id; }
}

// ── Service with constructor injection ──────────────────────────
@Service
class UserService {
    private final UserRepository repo;
    private final NotificationService notifier;

    // Constructor injection — recommended
    @Autowired
    public UserService(UserRepository repo, NotificationService notifier) {
        this.repo = repo;
        this.notifier = notifier;
    }

    public void processUser(int id) {
        String user = repo.findById(id);
        notifier.send("Processed: " + user);
    }

    @PostConstruct
    public void init() { System.out.println("UserService initialized"); }

    @PreDestroy
    public void cleanup() { System.out.println("UserService shutting down"); }
}

// ── Configuration ────────────────────────────────────────────────
@Configuration
@ComponentScan
class AppConfig {
    // Beans auto-detected via @Service/@Repository annotations
    // Could also define manually:
    // @Bean public UserService userService(UserRepository r, NotificationService n) {
    //     return new UserService(r, n);
    // }
}

// ── Main ─────────────────────────────────────────────────────────
public class SpringCoreDemo {
    public static void main(String[] args) {
        try (var ctx = new org.springframework.context.annotation.AnnotationConfigApplicationContext(AppConfig.class)) {
            UserService svc = ctx.getBean(UserService.class);
            svc.processUser(42);
        } // triggers @PreDestroy
    }
}

import org.springframework.beans.factory.annotation.*;
import org.springframework.context.annotation.*;
import org.springframework.stereotype.*;

interface PaymentGateway { String charge(double amount); }

@Service("stripe")
class StripeGateway implements PaymentGateway {
    @Override public String charge(double amount) { return "Stripe charged $" + amount; }
}

@Service("paypal")
@Primary // default when no @Qualifier specified
class PayPalGateway implements PaymentGateway {
    @Override public String charge(double amount) { return "PayPal charged $" + amount; }
}

@Profile("test")
@Service
class MockPaymentGateway implements PaymentGateway {
    @Override public String charge(double amount) { return "Mock charged $" + amount; }
}

@Service
class OrderService {
    @Autowired
    PaymentGateway defaultGateway; // gets PayPalGateway (@Primary)

    @Autowired @Qualifier("stripe")
    PaymentGateway stripeGateway;

    public void processOrder(double amount, boolean useStripe) {
        System.out.println(useStripe
            ? stripeGateway.charge(amount)
            : defaultGateway.charge(amount));
    }
}

@Configuration @ComponentScan
class PayConfig {}

public class QualifierDemo {
    public static void main(String[] args) {
        var ctx = new org.springframework.context.annotation.AnnotationConfigApplicationContext(PayConfig.class);
        OrderService order = ctx.getBean(OrderService.class);
        order.processOrder(99.99, false); // PayPal
        order.processOrder(199.99, true); // Stripe
        ctx.close();
    }
}

