public class Q1 {
    interface Logger { void log(String msg); }
    interface Database { String findUser(int id); }

    static class ConsoleLogger implements Logger {
        public void log(String msg) { System.out.println("[LOG] " + msg); }
    }
    static class FileLogger implements Logger {
        public void log(String msg) { System.out.println("[FILE] " + msg); }
    }
    static class H2Database implements Database {
        public String findUser(int id) { return "User#" + id; }
    }

    static class UserService {
        private final Database db;
        private final Logger logger;
        UserService(Database db, Logger logger) { this.db = db; this.logger = logger; }
        public void getUser(int id) {
            String user = db.findUser(id);
            logger.log("Found: " + user);
        }
    }

    public static void main(String[] args) {
        Database db = new H2Database();
        new UserService(db, new ConsoleLogger()).getUser(1); // [LOG] Found: User#1
        new UserService(db, new FileLogger()).getUser(2);   // [FILE] Found: User#2
    }
}

