import java.util.*;
import java.util.function.*;

public class Q2 {
    static class SimpleContainer {
        private final Map<String, Object>            singletons = new HashMap<>();
        private final Map<String, Supplier<Object>> prototypes  = new HashMap<>();
        private final Map<String, Supplier<Object>> allSuppliers = new HashMap<>();
        private final Set<String>                   isSingleton = new HashSet<>();

        public void registerSingleton(String name, Supplier<Object> s) {
            allSuppliers.put(name, s); isSingleton.add(name);
        }
        public void registerPrototype(String name, Supplier<Object> s) {
            allSuppliers.put(name, s);
        }
        public Object getBean(String name) {
            if (isSingleton.contains(name))
                return singletons.computeIfAbsent(name, k -> allSuppliers.get(k).get());
            return allSuppliers.get(name).get();
        }
    }

    public static void main(String[] args) {
        SimpleContainer c = new SimpleContainer();
        c.registerSingleton("db", Object::new);
        c.registerPrototype("req", Object::new);
        System.out.println(c.getBean("db") == c.getBean("db"));   // true
        System.out.println(c.getBean("req") == c.getBean("req")); // false
    }
}

