public class Q3 {
    static class ServiceA {
        ServiceB b;
        public void setB(ServiceB b) { this.b = b; } // setter injection
        public void doA() { System.out.println("A → " + b.name()); }
    }
    static class ServiceB {
        ServiceA a;
        public void setA(ServiceA a) { this.a = a; } // setter injection
        public String name() { return "ServiceB"; }
        public void doB() { System.out.println("B → " + a.getClass().getSimpleName()); }
    }
    public static void main(String[] args) {
        // Create instances first (no deps needed)
        ServiceA a = new ServiceA();
        ServiceB b = new ServiceB();
        // Then inject via setters
        a.setB(b);
        b.setA(a);
        a.doA(); // A → ServiceB
        b.doB(); // B → ServiceA
        // Real fix: refactor — circular deps indicate design problem
    }
}
